22→export async function unwrap(
23→    rpc: Rpc,
24→    payer: Signer,
25→    destination: PublicKey,
26→    owner: Signer,
27→    mint: PublicKey,
28→    amount?: number | bigint | BN,
29→    splInterfaceInfo?: SplInterfaceInfo,
30→    maxTopUp?: number,
31→    confirmOptions?: ConfirmOptions,
32→    decimals?: number,
33→): Promise<TransactionSignature> {
34→    const resolvedDecimals =
35→        decimals ?? (await getMintInterface(rpc, mint)).mint.decimals;
36→    const batches = await createUnwrapInstructions(
37→        rpc,
38→        destination,
39→        owner.publicKey,
40→        mint,
41→        resolvedDecimals,
42→        amount,
43→        payer.publicKey,
44→        splInterfaceInfo,
45→        maxTopUp,
46→    );
47→
48→    const additionalSigners = dedupeSigner(payer, [owner]);
49→    const { rest: loads, last: unwrapIxs } = sliceLast(batches);
50→
51→    await Promise.all(
52→        loads.map(async ixs => {
53→            const { blockhash } = await rpc.getLatestBlockhash();
54→            const tx = buildAndSignTx(ixs, payer, blockhash, additionalSigners);
55→            return sendAndConfirmTx(rpc, tx, confirmOptions);
56→        }),
57→    );
58→
59→    const { blockhash } = await rpc.getLatestBlockhash();
60→    const tx = buildAndSignTx(unwrapIxs, payer, blockhash, additionalSigners);
61→    return sendAndConfirmTx(rpc, tx, confirmOptions);
62→}
