 89→/** @internal */
 90→function parseTokenData(data: Buffer): {
 91→    mint: PublicKey;
 92→    owner: PublicKey;
 93→    amount: BN;
 94→    delegate: PublicKey | null;
 95→    state: number;
 96→    tlv: Buffer | null;
 97→} | null {
 98→    if (!data || data.length === 0) return null;
 99→
100→    try {
101→        let offset = 0;
102→        const mint = new PublicKey(data.slice(offset, offset + 32));
103→        offset += 32;
104→        const owner = new PublicKey(data.slice(offset, offset + 32));
105→        offset += 32;
106→        const amount = new BN(data.slice(offset, offset + 8), 'le');
107→        offset += 8;
108→        const delegateOption = data[offset];
109→        offset += 1;
110→        const delegate = delegateOption
111→            ? new PublicKey(data.slice(offset, offset + 32))
112→            : null;
113→        offset += 32;
114→        const state = data[offset];
115→        offset += 1;
116→        const tlvOption = data[offset];
117→        offset += 1;
118→        const tlv = tlvOption ? data.slice(offset) : null;
119→
120→        return {
121→            mint,
122→            owner,
123→            amount,
124→            delegate,
125→            state,
126→            tlv,
127→        };
128→    } catch (error) {
129→        console.error('Token data parsing error:', error);
130→        return null;
131→    }
132→}
