175→const COMPRESSED_ONLY_DISCRIMINATOR = 31;
176→
177→/**
178→ * Extract delegated_amount from CompressedOnly extension in Borsh-serialized
179→ * TLV data (Vec<ExtensionStruct>).
180→ * @internal
181→ */
182→function extractDelegatedAmountFromTlv(tlv: Buffer | null): bigint | null {
183→    if (!tlv || tlv.length < 5) return null;
184→
185→    try {
186→        let offset = 0;
187→        const vecLen = tlv.readUInt32LE(offset);
188→        offset += 4;
189→
190→        for (let i = 0; i < vecLen; i++) {
191→            if (offset >= tlv.length) return null;
192→
193→            const discriminator = tlv[offset];
194→            offset += 1;
195→
196→            if (discriminator === COMPRESSED_ONLY_DISCRIMINATOR) {
197→                if (offset + 8 > tlv.length) return null;
198→                // delegated_amount is the first u64 field
199→                const lo = BigInt(tlv.readUInt32LE(offset));
200→                const hi = BigInt(tlv.readUInt32LE(offset + 4));

