 26→/** Result of associated token account validation */
 27→export interface AtaValidationResult {
 28→    valid: true;
 29→    type: AtaType;
 30→    programId: PublicKey;
 31→}
 32→
 33→/**
 34→ * Check if an associated token account address matches the expected derivation from mint+owner.
 35→ *
 36→ * Pass programId for fast path.
 37→ *
 38→ * @param ata                associated token account address to check
 39→ * @param mint               Mint address
 40→ * @param owner              Owner address
 41→ * @param programId          Optional: if known, only check this program's associated token account
 42→ * @param allowOwnerOffCurve Allow the owner to be off-curve (PDA)
 43→ * @returns                  Result with detected type, or throws on mismatch
 44→ * @internal
 45→ */
 46→export function checkAtaAddress(
 47→    ata: PublicKey,
 48→    mint: PublicKey,
 49→    owner: PublicKey,
 50→    programId?: PublicKey,
 51→    allowOwnerOffCurve = false,
 52→): AtaValidationResult {
 53→    // fast path
 54→    if (programId) {
 55→        const expected = getAssociatedTokenAddressSync(
 56→            mint,
 57→            owner,
 58→            allowOwnerOffCurve,
 59→            programId,
 60→            getAtaProgramId(programId),
 61→        );
 62→        if (ata.equals(expected)) {
 63→            return {
 64→                valid: true,
 65→                type: programIdToAtaType(programId),
 66→                programId,
 67→            };
 68→        }
 69→        throw new Error(
 70→            `ATA address mismatch for ${programId.toBase58()}. ` +
 71→                `Expected: ${expected.toBase58()}, got: ${ata.toBase58()}`,
 72→        );
 73→    }
 74→
 75→    let lightTokenExpected: PublicKey;
 76→    let splExpected: PublicKey;
 77→    let t22Expected: PublicKey;
 78→
 79→    // light-token
 80→    lightTokenExpected = getAssociatedTokenAddressSync(
 81→        mint,
 82→        owner,
 83→        allowOwnerOffCurve,
 84→        LIGHT_TOKEN_PROGRAM_ID,
 85→        getAtaProgramId(LIGHT_TOKEN_PROGRAM_ID),
 86→    );
 87→    if (ata.equals(lightTokenExpected)) {
 88→        return {
 89→            valid: true,
 90→            type: 'light-token',
 91→            programId: LIGHT_TOKEN_PROGRAM_ID,
 92→        };
 93→    }
 94→
 95→    // SPL
 96→    splExpected = getAssociatedTokenAddressSync(
 97→        mint,
 98→        owner,
 99→        allowOwnerOffCurve,
100→        TOKEN_PROGRAM_ID,
101→        getAtaProgramId(TOKEN_PROGRAM_ID),
102→    );
103→    if (ata.equals(splExpected)) {
104→        return { valid: true, type: 'spl', programId: TOKEN_PROGRAM_ID };
105→    }
106→
107→    // T22
108→    t22Expected = getAssociatedTokenAddressSync(
109→        mint,
110→        owner,
111→        allowOwnerOffCurve,
112→        TOKEN_2022_PROGRAM_ID,
113→        getAtaProgramId(TOKEN_2022_PROGRAM_ID),
114→    );
115→
116→    if (ata.equals(t22Expected)) {
117→        return {
118→            valid: true,
119→            type: 'token2022',
120→            programId: TOKEN_2022_PROGRAM_ID,
121→        };
122→    }
123→
124→    throw new Error(
125→        `ATA address does not match any valid derivation from mint+owner. ` +
126→            `Got: ${ata.toBase58()}, expected one of: ` +
127→            `light-token=${lightTokenExpected.toBase58()}, ` +
128→            `SPL=${splExpected.toBase58()}, ` +
129→            `T22=${t22Expected.toBase58()}`,
130→    );
131→}
132→
133→/**
134→ * Convert programId to AtaType
135→ * @internal
136→ */
137→function programIdToAtaType(programId: PublicKey): AtaType {
138→    if (programId.equals(LIGHT_TOKEN_PROGRAM_ID)) return 'light-token';
139→    if (programId.equals(TOKEN_PROGRAM_ID)) return 'spl';
140→    if (programId.equals(TOKEN_2022_PROGRAM_ID)) return 'token2022';
141→    throw new Error(`Unknown program ID: ${programId.toBase58()}`);
142→}
