 40→const TRANSFER_BASE_CU = 10_000;
 41→const CU_BUFFER_FACTOR = 1.3;
 42→
 43→export function calculateTransferCU(
 44→    loadBatch: InternalLoadBatch | null,
 45→): number {
 46→    const rawLoadCu = loadBatch ? rawLoadBatchComputeUnits(loadBatch) : 0;
 47→    const cu = Math.ceil((TRANSFER_BASE_CU + rawLoadCu) * CU_BUFFER_FACTOR);
 48→    return Math.max(50_000, Math.min(1_400_000, cu));
 49→}
