 51→/**
 52→ * Create a light-token transfer instruction.
 53→ *
 54→ * For light-token accounts with compressible extension, the program needs
 55→ * system_program and fee_payer to handle rent top-ups.
 56→ *
 57→ * @param source        Source light-token account
 58→ * @param destination   Destination light-token account
 59→ * @param owner         Owner of the source account (signer, also pays for compressible extension top-ups)
 60→ * @param amount        Amount to transfer
 61→ * @param feePayer      Optional fee payer for top-ups (defaults to owner)
 62→ * @returns Transaction instruction for light-token transfer
 63→ */
 64→export function createLightTokenTransferInstruction(
 65→    source: PublicKey,
 66→    destination: PublicKey,
 67→    owner: PublicKey,
 68→    amount: number | bigint,
 69→    feePayer?: PublicKey,
 70→): TransactionInstruction {
 71→    // Instruction data format:
 72→    // byte 0: discriminator (3)
 73→    // bytes 1-8: amount (u64 LE)
 74→    const data = Buffer.alloc(9);
 75→    data.writeUInt8(LIGHT_TOKEN_TRANSFER_DISCRIMINATOR, 0);
 76→    data.writeBigUInt64LE(BigInt(amount), 1);
 77→
 78→    const effectiveFeePayer = feePayer ?? owner;
 79→
 80→    // Account order per program:
 81→    // 0: source (writable)
 82→    // 1: destination (writable)
 83→    // 2: authority/owner (signer, writable for top-ups)
 84→    // 3: system_program (for top-ups via CPI)
 85→    // 4: fee_payer (signer, writable - pays for top-ups)
 86→    const keys = [
 87→        { pubkey: source, isSigner: false, isWritable: true },
 88→        { pubkey: destination, isSigner: false, isWritable: true },
 89→        { pubkey: owner, isSigner: true, isWritable: true },
 90→        { pubkey: SystemProgram.programId, isSigner: false, isWritable: false },
 91→        {
 92→            pubkey: effectiveFeePayer,
 93→            isSigner: !effectiveFeePayer.equals(owner), // Only mark as signer if different from owner (owner already signed)
 94→            isWritable: true,
 95→        },
 96→    ];
 97→
 98→    return new TransactionInstruction({
 99→        programId: LIGHT_TOKEN_PROGRAM_ID,
100→        keys,
101→        data,
102→    });
103→}
