143→export async function createTransferInterfaceInstructions(
144→    rpc: Rpc,
145→    payer: PublicKey,
146→    mint: PublicKey,
147→    amount: number | bigint | BN,
148→    sender: PublicKey,
149→    destination: PublicKey,
150→    decimals: number,
151→    options?: TransferOptions,
152→): Promise<TransactionInstruction[][]> {
153→    assertBetaEnabled();
154→
155→    const amountBigInt = BigInt(amount.toString());
156→
157→    if (amountBigInt <= BigInt(0)) {
158→        throw new Error('Transfer amount must be greater than zero.');
159→    }
160→
161→    const {
162→        wrap = false,
163→        programId = LIGHT_TOKEN_PROGRAM_ID,
164→        owner: optionsOwner,
165→        ...interfaceOptions
166→    } = options ?? {};
167→
168→    const effectiveOwner = optionsOwner ?? sender;
169→
170→    const isSplOrT22 =
171→        programId.equals(TOKEN_PROGRAM_ID) ||
172→        programId.equals(TOKEN_2022_PROGRAM_ID);
173→
174→    const senderAta = getAssociatedTokenAddressInterface(
175→        mint,
176→        effectiveOwner,
177→        false,
178→        programId,
179→    );
180→
181→    let senderInterface: AccountInterface;
182→    try {
183→        senderInterface = await _getAtaInterface(
184→            rpc,
185→            senderAta,
186→            effectiveOwner,
187→            mint,
188→            undefined,
189→            programId.equals(LIGHT_TOKEN_PROGRAM_ID) ? undefined : programId,
190→            wrap,
191→        );
192→    } catch (error) {
193→        if (error instanceof TokenAccountNotFoundError) {
194→            throw new Error('Sender has no token accounts for this mint.');
195→        }
196→        throw error;
197→    }
198→
199→    assertNotFrozen(senderInterface, 'transfer');
200→
201→    const isDelegate = !effectiveOwner.equals(sender);
202→    if (isDelegate) {
203→        if (!isAuthorityForInterface(senderInterface, sender)) {
204→            throw new Error(
205→                'Signer is not the owner or a delegate of the sender account.',
206→            );
207→        }
208→        const spendable = spendableAmountForAuthority(senderInterface, sender);
209→        if (amountBigInt > spendable) {
210→            throw new Error(
211→                `Insufficient delegated balance. Required: ${amountBigInt}, Available (delegate): ${spendable}`,
212→            );
213→        }
214→        senderInterface = filterInterfaceForAuthority(senderInterface, sender);
215→    } else {
216→        if (senderInterface.parsed.amount < amountBigInt) {
217→            throw new Error(
218→                `Insufficient balance. Required: ${amountBigInt}, Available: ${senderInterface.parsed.amount}`,
219→            );
220→        }
221→    }
222→
223→    const internalBatches = await _buildLoadBatches(
224→        rpc,
225→        payer,
226→        senderInterface,
227→        interfaceOptions,
228→        wrap,
229→        senderAta,
230→        amountBigInt,
231→        sender,
232→        decimals,
233→    );
234→
235→    let transferIx: TransactionInstruction;
236→    if (isSplOrT22 && !wrap) {
237→        transferIx = createTransferCheckedInstruction(
238→            senderAta,
239→            mint,
240→            destination,
241→            sender,
242→            amountBigInt,
243→            decimals,
244→            [],
245→            programId,
246→        );
247→    } else {
248→        transferIx = createLightTokenTransferCheckedInstruction(
249→            senderAta,
250→            destination,
251→            mint,
252→            sender,
253→            amountBigInt,
254→            decimals,
255→            payer,
256→        );
257→    }
258→
259→    const numSigners = payer.equals(sender) ? 1 : 2;
260→
261→    if (internalBatches.length === 0) {
262→        const cu = calculateTransferCU(null);
263→        const txIxs = [
264→            ComputeBudgetProgram.setComputeUnitLimit({ units: cu }),
265→            transferIx,
266→        ];
267→        assertTransactionSizeWithinLimit(txIxs, numSigners, 'Batch');
268→        return [txIxs];
269→    }
270→
271→    if (internalBatches.length === 1) {
272→        const batch = internalBatches[0];
273→        const cu = calculateTransferCU(batch);
274→        const txIxs = [
275→            ComputeBudgetProgram.setComputeUnitLimit({ units: cu }),
276→            ...batch.instructions,
277→            transferIx,
278→        ];
279→        assertTransactionSizeWithinLimit(txIxs, numSigners, 'Batch');
280→        return [txIxs];
281→    }
282→
283→    const result: TransactionInstruction[][] = [];
284→
285→    for (let i = 0; i < internalBatches.length - 1; i++) {
286→        const batch = internalBatches[i];
287→        const cu = calculateLoadBatchComputeUnits(batch);
288→        const txIxs = [
289→            ComputeBudgetProgram.setComputeUnitLimit({ units: cu }),
290→            ...batch.instructions,
291→        ];
292→        assertTransactionSizeWithinLimit(txIxs, numSigners, 'Batch');
293→        result.push(txIxs);
294→    }
295→
296→    const lastBatch = internalBatches[internalBatches.length - 1];
297→    const lastCu = calculateTransferCU(lastBatch);
298→    const lastTxIxs = [
299→        ComputeBudgetProgram.setComputeUnitLimit({ units: lastCu }),
300→        ...lastBatch.instructions,
301→        transferIx,
302→    ];
303→    assertTransactionSizeWithinLimit(lastTxIxs, numSigners, 'Batch');
304→    result.push(lastTxIxs);
305→
306→    return result;
307→}
