 41→export const MAX_INPUT_ACCOUNTS = 8;
 42→
 43→function chunkArray<T>(array: T[], chunkSize: number): T[][] {
 44→    const chunks: T[][] = [];
 45→    for (let i = 0; i < array.length; i += chunkSize) {
 46→        chunks.push(array.slice(i, i + chunkSize));
 47→    }
 48→    return chunks;
 49→}
 50→
 51→export function selectInputsForAmount(
 52→    accounts: ParsedTokenAccount[],
 53→    neededAmount: bigint,
 54→): ParsedTokenAccount[] {
 55→    if (accounts.length === 0 || neededAmount <= BigInt(0)) return [];
 56→
 57→    const sorted = [...accounts].sort((a, b) => {
 58→        const amtA = BigInt(a.parsed.amount.toString());
 59→        const amtB = BigInt(b.parsed.amount.toString());
 60→        if (amtB > amtA) return 1;
 61→        if (amtB < amtA) return -1;
 62→        return 0;
 63→    });
 64→
 65→    let accumulated = BigInt(0);
 66→    let countNeeded = 0;
 67→    for (const acc of sorted) {
 68→        countNeeded++;
 69→        accumulated += BigInt(acc.parsed.amount.toString());
 70→        if (accumulated >= neededAmount) break;
 71→    }
 72→
 73→    const selectCount = Math.min(
 74→        Math.max(countNeeded, MAX_INPUT_ACCOUNTS),
 75→        sorted.length,
 76→    );
 77→
 78→    return sorted.slice(0, selectCount);
 79→}
 80→
 81→function assertUniqueInputHashes(chunks: ParsedTokenAccount[][]): void {
 82→    const seen = new Set<string>();
 83→    for (const chunk of chunks) {
 84→        for (const acc of chunk) {
 85→            const hashStr = acc.compressedAccount.hash.toString();
 86→            if (seen.has(hashStr)) {
 87→                throw new Error(
 88→                    `Duplicate compressed account hash across chunks: ${hashStr}. ` +
 89→                        `Each compressed account must appear in exactly one chunk.`,
 90→                );
 91→            }
 92→            seen.add(hashStr);
 93→        }
 94→    }
 95→}
