 97→export function getCompressedTokenAccountsFromAtaSources(
 98→    sources: TokenAccountSource[],
 99→): ParsedTokenAccount[] {
100→    return sources
101→        .filter(source => source.loadContext !== undefined)
102→        .filter(source => COLD_SOURCE_TYPES.has(source.type))
103→        .map(source => {
104→            const fullData = source.accountInfo.data;
105→            const discriminatorBytes = fullData.subarray(
106→                0,
107→                Math.min(8, fullData.length),
108→            );
109→            const accountDataBytes =
110→                fullData.length > 8 ? fullData.subarray(8) : Buffer.alloc(0);
111→
112→            const compressedAccount = {
113→                treeInfo: source.loadContext!.treeInfo,
114→                hash: source.loadContext!.hash,
115→                leafIndex: source.loadContext!.leafIndex,
116→                proveByIndex: source.loadContext!.proveByIndex,
117→                owner: source.accountInfo.owner,
118→                lamports: bn(source.accountInfo.lamports),
119→                address: null,
120→                data:
121→                    fullData.length === 0
122→                        ? null
123→                        : {
124→                              discriminator: Array.from(discriminatorBytes),
125→                              data: Buffer.from(accountDataBytes),
126→                              dataHash: new Array(32).fill(0),
127→                          },
128→                readOnly: false,
129→            };
130→
131→            const state = !source.parsed.isInitialized
132→                ? 0
133→                : source.parsed.isFrozen
134→                  ? 2
135→                  : 1;
136→
137→            return {
138→                compressedAccount: compressedAccount as any,
139→                parsed: {
140→                    mint: source.parsed.mint,
141→                    owner: source.parsed.owner,
142→                    amount: bn(source.parsed.amount.toString()),
143→                    delegate: source.parsed.delegate,
144→                    state,
145→                    tlv:
146→                        source.parsed.tlvData.length > 0
147→                            ? source.parsed.tlvData
148→                            : null,
149→                },
150→            } satisfies ParsedTokenAccount;
151→        });
152→}
