215→/** @internal */
216→export function convertTokenDataToAccount(
217→    address: PublicKey,
218→    tokenData: {
219→        mint: PublicKey;
220→        owner: PublicKey;
221→        amount: BN;
222→        delegate: PublicKey | null;
223→        state: number;
224→        tlv: Buffer | null;
225→    },
226→): Account {
227→    // Determine delegatedAmount for compressed TokenData:
228→    // 1. If CompressedOnly extension present in TLV, use its delegated_amount
229→    // 2. If delegate is set (regular compressed approve), the entire compressed
230→    //    account's amount is the delegation (change goes to a separate account)
231→    // 3. Otherwise, 0
232→    let delegatedAmount = BigInt(0);
233→    const extensionDelegatedAmount = extractDelegatedAmountFromTlv(
234→        tokenData.tlv,
235→    );
236→    if (extensionDelegatedAmount !== null) {
237→        delegatedAmount = extensionDelegatedAmount;
238→    } else if (tokenData.delegate) {
239→        delegatedAmount = BigInt(tokenData.amount.toString());
240→    }
241→
242→    return {
243→        address,
244→        mint: tokenData.mint,
245→        owner: tokenData.owner,
246→        amount: BigInt(tokenData.amount.toString()),
247→        delegate: tokenData.delegate,
248→        delegatedAmount,
249→        isInitialized: tokenData.state !== AccountState.Uninitialized,
250→        isFrozen: tokenData.state === AccountState.Frozen,
251→        isNative: false,
252→        rentExemptReserve: null,
253→        closeAuthority: null,
254→        tlvData: tokenData.tlv ? Buffer.from(tokenData.tlv) : Buffer.alloc(0),
255→    };
256→}
