350→ *
351→ * @param rpc                RPC connection
352→ * @param ata                Associated token address
353→ * @param owner              Owner public key
354→ * @param mint               Mint public key
355→ * @param commitment         Optional commitment level
356→ * @param programId          Optional program ID
357→ * @param wrap               Include SPL/T22 balances (default: false)
358→ * @param allowOwnerOffCurve Allow owner to be off-curve (PDA)
359→ * @returns AccountInterface with associated token account metadata
360→ */
361→export async function getAtaInterface(
362→    rpc: Rpc,
363→    ata: PublicKey,
364→    owner: PublicKey,
365→    mint: PublicKey,
366→    commitment?: Commitment,
367→    programId?: PublicKey,
368→    wrap = false,
369→    allowOwnerOffCurve = false,
370→): Promise<AccountInterface> {
371→    assertBetaEnabled();
372→
373→    // Invariant: ata MUST match a valid derivation from mint+owner.
374→    // Hot path: if programId provided, only validate against that program.
375→    // For wrap=true, additionally require light-token associated token account.
376→    const validation = checkAtaAddress(
377→        ata,
378→        mint,
379→        owner,
380→        programId,
381→        allowOwnerOffCurve,
382→    );
383→
384→    if (wrap && validation.type !== 'light-token') {
385→        throw new Error(
386→            `For wrap=true, ata must be the light-token ATA. Got ${validation.type} ATA instead.`,
387→        );
388→    }
389→
390→    // Pass both ata address AND fetchByOwner for proper lookups:
391→    // - address is used for on-chain account fetching
392→    // - fetchByOwner is used for light-token lookup by owner+mint
393→    const result = await _getAccountInterface(
394→        rpc,
395→        ata,
396→        commitment,
397→        programId,
398→        {
399→            owner,
400→            mint,
401→        },
402→        wrap,
403→    );
404→    result._isAta = true;
405→    result._owner = owner;
406→    result._mint = mint;
407→    return result;
408→}
