801→/** @internal */
802→async function getSplOrToken2022AccountInterface(
803→    rpc: Rpc,
804→    address: PublicKey | undefined,
805→    commitment: Commitment | undefined,
806→    programId: PublicKey,
807→    fetchByOwner?: { owner: PublicKey; mint: PublicKey },
808→): Promise<AccountInterface> {
809→    if (!address) {
810→        if (!fetchByOwner) {
811→            throw new Error(ERR_FETCH_BY_OWNER_REQUIRED);
812→        }
813→        address = getAssociatedTokenAddressSync(
814→            fetchByOwner.mint,
815→            fetchByOwner.owner,
816→            false,
817→            programId,
818→            getAtaProgramId(programId),
819→        );
820→    }
821→
822→    const hotType: TokenAccountSource['type'] = programId.equals(
823→        TOKEN_PROGRAM_ID,
824→    )
825→        ? TokenAccountSourceType.Spl
826→        : TokenAccountSourceType.Token2022;
827→
828→    const coldType: TokenAccountSource['type'] = programId.equals(
829→        TOKEN_PROGRAM_ID,
830→    )
831→        ? TokenAccountSourceType.SplCold
832→        : TokenAccountSourceType.Token2022Cold;
833→
834→    // Fetch hot and cold in parallel (neither is required individually)
835→    const hotPromise = rpc
836→        .getAccountInfo(address, commitment)
837→        .catch(() => null);
838→    const coldPromise = fetchByOwner
839→        ? rpc
840→              .getCompressedTokenAccountsByOwner(fetchByOwner.owner, {
841→                  mint: fetchByOwner.mint,
842→              })
843→              .catch(() => ({ items: [] as any[] }))
844→        : Promise.resolve({ items: [] as any[] });
845→
846→    const [hotInfo, coldResult] = await Promise.all([hotPromise, coldPromise]);
847→
848→    const sources: TokenAccountSource[] = [];
849→
850→    // Hot SPL/T22 account (may not exist)
851→    if (hotInfo) {
852→        try {
853→            const account = unpackAccountSPL(address, hotInfo, programId);
854→            sources.push({
855→                type: hotType,
856→                address,
857→                amount: account.amount,
858→                accountInfo: hotInfo,
859→                parsed: account,
860→            });
861→        } catch {
862→            // Not a valid SPL/T22 account at this address, skip
863→        }
864→    }
865→
866→    // Cold (compressed) accounts
867→    for (const item of coldResult.items) {
868→        const compressedAccount = item.compressedAccount;
869→        if (
870→            compressedAccount &&
871→            compressedAccount.data &&
872→            compressedAccount.data.data.length > 0 &&
873→            compressedAccount.owner.equals(LIGHT_TOKEN_PROGRAM_ID)
874→        ) {
875→            const parsedCold = parseLightTokenCold(address, compressedAccount);
876→            sources.push({
877→                type: coldType,
878→                address,
879→                amount: parsedCold.parsed.amount,
880→                accountInfo: parsedCold.accountInfo,
881→                loadContext: parsedCold.loadContext,
882→                parsed: parsedCold.parsed,
883→            });
884→        }
885→    }
886→
887→    if (sources.length === 0) {
888→        throw new TokenAccountNotFoundError();
889→    }
890→
891→    return buildAccountInterfaceFromSources(sources, address);
892→}
