 21→export interface InterfaceOptions {
 22→    splInterfaceInfos?: SplInterfaceInfo[];
 23→    /**
 24→     * ATA owner (authority owner) used to derive the ATA when the signer is a
 25→     * delegate. For owner-signed flows, omit this field.
 26→     */
 27→    owner?: PublicKey;
