 30→export async function transferInterface(
 31→    rpc: Rpc,
 32→    payer: Signer,
 33→    source: PublicKey,
 34→    mint: PublicKey,
 35→    destination: PublicKey,
 36→    owner: Signer,
 37→    amount: number | bigint | BN,
 38→    programId: PublicKey = LIGHT_TOKEN_PROGRAM_ID,
 39→    confirmOptions?: ConfirmOptions,
 40→    options?: InterfaceOptions,
 41→    wrap = false,
 42→    decimals?: number,
 43→): Promise<TransactionSignature> {
 44→    assertBetaEnabled();
 45→
 46→    const effectiveOwner = options?.owner ?? owner.publicKey;
 47→    const expectedSource = getAssociatedTokenAddressInterface(
 48→        mint,
 49→        effectiveOwner,
 50→        false,
 51→        programId,
 52→    );
 53→    if (!source.equals(expectedSource)) {
 54→        throw new Error(
 55→            `Source mismatch. Expected ${expectedSource.toBase58()}, got ${source.toBase58()}`,
 56→        );
 57→    }
 58→
 59→    const amountBigInt = BigInt(amount.toString());
 60→
 61→    const resolvedDecimals =
 62→        decimals ?? (await getMintInterface(rpc, mint)).mint.decimals;
 63→    const batches = await createTransferInterfaceInstructions(
 64→        rpc,
 65→        payer.publicKey,
 66→        mint,
 67→        amountBigInt,
 68→        owner.publicKey,
 69→        destination,
 70→        resolvedDecimals,
 71→        {
 72→            ...options,
 73→            wrap,
 74→            programId,
 75→        },
 76→    );
 77→
 78→    const additionalSigners = dedupeSigner(payer, [owner]);
 79→    const { rest: loads, last: transferIxs } = sliceLast(batches);
 80→
 81→    await Promise.all(
 82→        loads.map(async ixs => {
 83→            const { blockhash } = await rpc.getLatestBlockhash();
 84→            const tx = buildAndSignTx(ixs, payer, blockhash, additionalSigners);
 85→            return sendAndConfirmTx(rpc, tx, confirmOptions);
 86→        }),
 87→    );
 88→
 89→    const { blockhash } = await rpc.getLatestBlockhash();
 90→    const tx = buildAndSignTx(transferIxs, payer, blockhash, additionalSigners);
 91→    return sendAndConfirmTx(rpc, tx, confirmOptions);
 92→}
 93→
 94→export interface TransferOptions extends InterfaceOptions {
 95→    wrap?: boolean;
 96→    programId?: PublicKey;
 97→}
