 99→export function sliceLast<T>(items: T[]): { rest: T[]; last: T } {
100→    if (items.length === 0) {
101→        throw new Error('sliceLast: array must not be empty');
102→    }
103→    return { rest: items.slice(0, -1), last: items.at(-1)! };
104→}
