  89→/** @internal */
  90→function parseTokenData(data: Buffer): {
  91→    mint: PublicKey;
  92→    owner: PublicKey;
  93→    amount: BN;
  94→    delegate: PublicKey | null;
  95→    state: number;
  96→    tlv: Buffer | null;
  97→} | null {
  98→    if (!data || data.length === 0) return null;
  99→
 100→    try {
 101→        let offset = 0;
 102→        const mint = new PublicKey(data.slice(offset, offset + 32));
 103→        offset += 32;
 104→        const owner = new PublicKey(data.slice(offset, offset + 32));
 105→        offset += 32;
 106→        const amount = new BN(data.slice(offset, offset + 8), 'le');
 107→        offset += 8;
 108→        const delegateOption = data[offset];
 109→        offset += 1;
 110→        const delegate = delegateOption
 111→            ? new PublicKey(data.slice(offset, offset + 32))
 112→            : null;
 113→        offset += 32;
 114→        const state = data[offset];
 115→        offset += 1;
 116→        const tlvOption = data[offset];
 117→        offset += 1;
 118→        const tlv = tlvOption ? data.slice(offset) : null;
 119→
 120→        return {
 121→            mint,
 122→            owner,
 123→            amount,
 124→            delegate,
 125→            state,
 126→            tlv,
 127→        };
 128→    } catch (error) {
 129→        console.error('Token data parsing error:', error);
 130→        return null;
 131→    }
 132→}
 133→
 134→/**
 135→ * Known extension data sizes by Borsh enum discriminator.
 136→ * undefined = variable-length (cannot skip without full parsing).
 137→ * @internal
 138→ */
 139→const EXTENSION_DATA_SIZES: Record<number, number | undefined> = {
 140→    0: 0,
 141→    1: 0,
 142→    2: 0,
 143→    3: 0,
 144→    4: 0,
 145→    5: 0,
 146→    6: 0,
 147→    7: 0,
 148→    8: 0,
 149→    9: 0,
 150→    10: 0,
 151→    11: 0,
 152→    12: 0,
 153→    13: 0,
 154→    14: 0,
 155→    15: 0,
 156→    16: 0,
 157→    17: 0,
 158→    18: 0,
 159→    19: undefined, // TokenMetadata (variable)
 160→    20: 0,
 161→    21: 0,
 162→    22: 0,
 163→    23: 0,
 164→    24: 0,
 165→    25: 0,
 166→    26: 0,
 167→    27: 0, // PausableAccountExtension (unit struct)
 168→    28: 0, // PermanentDelegateAccountExtension (unit struct)
 169→    29: 8, // TransferFeeAccountExtension (u64)
 170→    30: 1, // TransferHookAccountExtension (u8)
 171→    31: 17, // CompressedOnlyExtension (u64 + u64 + u8)
 172→    32: undefined, // CompressibleExtension (variable)
 173→};
 174→
 175→const COMPRESSED_ONLY_DISCRIMINATOR = 31;
 176→
 177→/**
 178→ * Extract delegated_amount from CompressedOnly extension in Borsh-serialized
 179→ * TLV data (Vec<ExtensionStruct>).
 180→ * @internal
 181→ */
 182→function extractDelegatedAmountFromTlv(tlv: Buffer | null): bigint | null {
 183→    if (!tlv || tlv.length < 5) return null;
 184→
 185→    try {
 186→        let offset = 0;
 187→        const vecLen = tlv.readUInt32LE(offset);
 188→        offset += 4;
 189→
 190→        for (let i = 0; i < vecLen; i++) {
 191→            if (offset >= tlv.length) return null;
 192→
 193→            const discriminator = tlv[offset];
 194→            offset += 1;
 195→
 196→            if (discriminator === COMPRESSED_ONLY_DISCRIMINATOR) {
 197→                if (offset + 8 > tlv.length) return null;
 198→                // delegated_amount is the first u64 field
 199→                const lo = BigInt(tlv.readUInt32LE(offset));
 200→                const hi = BigInt(tlv.readUInt32LE(offset + 4));
 201→                return lo | (hi << BigInt(32));
 202→            }
 203→
 204→            const size = EXTENSION_DATA_SIZES[discriminator];
 205→            if (size === undefined) return null;
 206→            offset += size;
 207→        }
 208→    } catch {
 209→        return null;
 210→    }
 211→
 212→    return null;
 213→}
