 258→/** Convert compressed account to AccountInfo */
 259→export function toAccountInfo(
 260→    compressedAccount: CompressedAccountWithMerkleContext,
 261→): AccountInfo<Buffer> {
 262→    const dataDiscriminatorBuffer: Buffer = Buffer.from(
 263→        compressedAccount.data!.discriminator,
 264→    );
 265→    const dataBuffer: Buffer = Buffer.from(compressedAccount.data!.data);
 266→    const data: Buffer = Buffer.concat([dataDiscriminatorBuffer, dataBuffer]);
 267→
 268→    return {
 269→        executable: false,
 270→        owner: compressedAccount.owner,
 271→        lamports: compressedAccount.lamports.toNumber(),
 272→        data,
 273→        rentEpoch: undefined,
 274→    };
 275→}
