 277→/** @internal */
 278→export function parseLightTokenHot(
 279→    address: PublicKey,
 280→    accountInfo: AccountInfo<Buffer>,
 281→): {
 282→    accountInfo: AccountInfo<Buffer>;
 283→    loadContext: undefined;
 284→    parsed: Account;
 285→    isCold: false;
 286→} {
 287→    // Hot light-token accounts use SPL-compatible layout with 4-byte COption tags.
 288→    // unpackAccountSPL correctly parses all fields including delegatedAmount,
 289→    // isNative, and closeAuthority.
 290→    const parsed = unpackAccountSPL(
 291→        address,
 292→        accountInfo,
 293→        LIGHT_TOKEN_PROGRAM_ID,
 294→    );
 295→    return {
 296→        accountInfo,
 297→        loadContext: undefined,
 298→        parsed,
 299→        isCold: false,
 300→    };
 301→}
