 303→/** @internal */
 304→export function parseLightTokenCold(
 305→    address: PublicKey,
 306→    compressedAccount: CompressedAccountWithMerkleContext,
 307→): {
 308→    accountInfo: AccountInfo<Buffer>;
 309→    loadContext: MerkleContext;
 310→    parsed: Account;
 311→    isCold: true;
 312→} {
 313→    const parsed = parseTokenData(compressedAccount.data!.data);
 314→    if (!parsed) throw new Error('Invalid token data');
 315→    return {
 316→        accountInfo: toAccountInfo(compressedAccount),
 317→        loadContext: {
 318→            treeInfo: compressedAccount.treeInfo,
 319→            hash: compressedAccount.hash,
 320→            leafIndex: compressedAccount.leafIndex,
 321→            proveByIndex: compressedAccount.proveByIndex,
 322→        },
 323→        parsed: convertTokenDataToAccount(address, parsed),
 324→        isCold: true,
 325→    };
 326→}
