 510→/**
 511→ * Retrieve information about a token account SPL/T22/light-token.
 512→ * @internal
 513→ */
 514→async function _getAccountInterface(
 515→    rpc: Rpc,
 516→    address?: PublicKey,
 517→    commitment?: Commitment,
 518→    programId?: PublicKey,
 519→    fetchByOwner?: {
 520→        owner: PublicKey;
 521→        mint: PublicKey;
 522→    },
 523→    wrap = false,
 524→): Promise<AccountInterface> {
 525→    // At least one of address or fetchByOwner is required.
 526→    // Both can be provided: address for on-chain lookup, fetchByOwner for
 527→    // light-token lookup by owner+mint (useful for PDA owners where
 528→    // address derivation might not work with standard allowOwnerOffCurve=false).
 529→    if (!address && !fetchByOwner) {
 530→        throw new Error('One of address or fetchByOwner is required');
 531→    }
 532→
 533→    // Unified mode (auto-detect: light-token + optional SPL/T22)
 534→    if (!programId) {
 535→        return getUnifiedAccountInterface(
 536→            rpc,
 537→            address,
 538→            commitment,
 539→            fetchByOwner,
 540→            wrap,
 541→        );
 542→    }
 543→
 544→    // light-token-only mode
 545→    if (programId.equals(LIGHT_TOKEN_PROGRAM_ID)) {
 546→        return getLightTokenAccountInterface(
 547→            rpc,
 548→            address,
 549→            commitment,
 550→            fetchByOwner,
 551→        );
 552→    }
 553→
 554→    // SPL / Token-2022 only
 555→    if (
 556→        programId.equals(TOKEN_PROGRAM_ID) ||
 557→        programId.equals(TOKEN_2022_PROGRAM_ID)
 558→    ) {
 559→        return getSplOrToken2022AccountInterface(
 560→            rpc,
 561→            address,
 562→            commitment,
 563→            programId,
 564→            fetchByOwner,
 565→        );
 566→    }
 567→
 568→    throw new Error(`Unsupported program ID: ${programId.toBase58()}`);
 569→}
