 571→/** @internal */
 572→async function getUnifiedAccountInterface(
 573→    rpc: Rpc,
 574→    address: PublicKey | undefined,
 575→    commitment: Commitment | undefined,
 576→    fetchByOwner: { owner: PublicKey; mint: PublicKey } | undefined,
 577→    wrap: boolean,
 578→): Promise<AccountInterface> {
 579→    // Canonical address for unified mode is always the light-token associated token account
 580→    const lightTokenAta =
 581→        address ??
 582→        getAssociatedTokenAddressSync(
 583→            fetchByOwner!.mint,
 584→            fetchByOwner!.owner,
 585→            false,
 586→            LIGHT_TOKEN_PROGRAM_ID,
 587→            getAtaProgramId(LIGHT_TOKEN_PROGRAM_ID),
 588→        );
 589→
 590→    const fetchPromises: Promise<{
 591→        accountInfo: AccountInfo<Buffer>;
 592→        parsed: Account;
 593→        isCold: boolean;
 594→        loadContext?: MerkleContext;
 595→    }>[] = [];
 596→    const fetchTypes: TokenAccountSource['type'][] = [];
 597→    const fetchAddresses: PublicKey[] = [];
 598→
 599→    // light-token hot
 600→    fetchPromises.push(_tryFetchLightTokenHot(rpc, lightTokenAta, commitment));
 601→    fetchTypes.push(TokenAccountSourceType.LightTokenHot);
 602→    fetchAddresses.push(lightTokenAta);
 603→
 604→    // SPL / Token-2022 (only when wrap is enabled)
 605→    if (wrap) {
 606→        // Always derive SPL/T22 addresses from owner+mint, not from the passed
 607→        // light-token address. SPL and T22 associated token accounts are different from light-token associated token accounts.
 608→        if (!fetchByOwner) {
 609→            throw new Error(
 610→                'fetchByOwner is required for wrap=true to derive SPL/T22 addresses',
 611→            );
 612→        }
 613→        const splTokenAta = getAssociatedTokenAddressSync(
 614→            fetchByOwner.mint,
 615→            fetchByOwner.owner,
 616→            false,
 617→            TOKEN_PROGRAM_ID,
 618→            getAtaProgramId(TOKEN_PROGRAM_ID),
 619→        );
 620→        const token2022Ata = getAssociatedTokenAddressSync(
 621→            fetchByOwner.mint,
 622→            fetchByOwner.owner,
 623→            false,
 624→            TOKEN_2022_PROGRAM_ID,
 625→            getAtaProgramId(TOKEN_2022_PROGRAM_ID),
 626→        );
 627→
 628→        fetchPromises.push(_tryFetchSpl(rpc, splTokenAta, commitment));
 629→        fetchTypes.push(TokenAccountSourceType.Spl);
 630→        fetchAddresses.push(splTokenAta);
 631→
 632→        fetchPromises.push(_tryFetchToken2022(rpc, token2022Ata, commitment));
 633→        fetchTypes.push(TokenAccountSourceType.Token2022);
 634→        fetchAddresses.push(token2022Ata);
 635→    }
 636→
 637→    // Fetch ALL cold light-token accounts (not just one) - important for V1/V2 detection
 638→    const coldAccountsPromise = fetchByOwner
 639→        ? rpc.getCompressedTokenAccountsByOwner(fetchByOwner.owner, {
 640→              mint: fetchByOwner.mint,
 641→          })
 642→        : rpc.getCompressedTokenAccountsByOwner(address!);
 643→
 644→    const [hotResults, coldResult] = await Promise.all([
 645→        Promise.allSettled(fetchPromises),
 646→        coldAccountsPromise.catch(() => ({ items: [] })),
 647→    ]);
 648→
 649→    // collect all successful hot results
 650→    const sources: TokenAccountSource[] = [];
 651→
 652→    for (let i = 0; i < hotResults.length; i++) {
 653→        const result = hotResults[i];
 654→        if (result.status === 'fulfilled') {
 655→            const value = result.value;
 656→            sources.push({
 657→                type: fetchTypes[i],
 658→                address: fetchAddresses[i],
 659→                amount: value.parsed.amount,
 660→                accountInfo: value.accountInfo,
 661→                loadContext: value.loadContext,
 662→                parsed: value.parsed,
 663→            });
 664→        }
 665→    }
 666→
 667→    // Add ALL cold light-token accounts (handles both V1 and V2)
 668→    for (const item of coldResult.items) {
 669→        const compressedAccount = item.compressedAccount;
 670→        if (
 671→            compressedAccount &&
 672→            compressedAccount.data &&
 673→            compressedAccount.data.data.length > 0 &&
 674→            compressedAccount.owner.equals(LIGHT_TOKEN_PROGRAM_ID)
 675→        ) {
 676→            const parsed = parseLightTokenCold(
 677→                lightTokenAta,
 678→                compressedAccount,
 679→            );
 680→            sources.push({
 681→                type: TokenAccountSourceType.LightTokenCold,
 682→                address: lightTokenAta,
 683→                amount: parsed.parsed.amount,
 684→                accountInfo: parsed.accountInfo,
 685→                loadContext: parsed.loadContext,
 686→                parsed: parsed.parsed,
 687→            });
 688→        }
 689→    }
 690→
 691→    // account not found
 692→    if (sources.length === 0) {
 693→        throw new TokenAccountNotFoundError();
 694→    }
 695→
 696→    // priority order: light-token hot > light-token cold > SPL/T22
 697→    const priority: TokenAccountSource['type'][] = [
 698→        TokenAccountSourceType.LightTokenHot,
 699→        TokenAccountSourceType.LightTokenCold,
 700→        TokenAccountSourceType.Spl,
 701→        TokenAccountSourceType.Token2022,
 702→    ];
 703→
 704→    sources.sort((a, b) => {
 705→        const aIdx = priority.indexOf(a.type);
 706→        const bIdx = priority.indexOf(b.type);
 707→        return aIdx - bIdx;
 708→    });
 709→
 710→    return buildAccountInterfaceFromSources(sources, lightTokenAta);
 711→}
