 713→/** @internal */
 714→async function getLightTokenAccountInterface(
 715→    rpc: Rpc,
 716→    address: PublicKey | undefined,
 717→    commitment: Commitment | undefined,
 718→    fetchByOwner?: { owner: PublicKey; mint: PublicKey },
 719→): Promise<AccountInterface> {
 720→    // Derive address if not provided
 721→    if (!address) {
 722→        if (!fetchByOwner) {
 723→            throw new Error(ERR_FETCH_BY_OWNER_REQUIRED);
 724→        }
 725→        address = getAssociatedTokenAddressSync(
 726→            fetchByOwner.mint,
 727→            fetchByOwner.owner,
 728→            false,
 729→            LIGHT_TOKEN_PROGRAM_ID,
 730→            getAtaProgramId(LIGHT_TOKEN_PROGRAM_ID),
 731→        );
 732→    }
 733→
 734→    const [onchainResult, compressedResult] = await Promise.allSettled([
 735→        rpc.getAccountInfo(address, commitment),
 736→        // Fetch compressed: by owner+mint for associated token accounts, by address for non-ATAs
 737→        fetchByOwner
 738→            ? rpc.getCompressedTokenAccountsByOwner(fetchByOwner.owner, {
 739→                  mint: fetchByOwner.mint,
 740→              })
 741→            : rpc.getCompressedTokenAccountsByOwner(address),
 742→    ]);
 743→
 744→    const onchainAccount =
 745→        onchainResult.status === 'fulfilled' ? onchainResult.value : null;
 746→    const compressedAccounts =
 747→        compressedResult.status === 'fulfilled'
 748→            ? compressedResult.value.items.map(item => item.compressedAccount)
 749→            : [];
 750→
 751→    const sources: TokenAccountSource[] = [];
 752→
 753→    // Collect light-token associated token account (hot balance)
 754→    if (onchainAccount && onchainAccount.owner.equals(LIGHT_TOKEN_PROGRAM_ID)) {
 755→        const parsed = parseLightTokenHot(address, onchainAccount);
 756→        sources.push({
 757→            type: TokenAccountSourceType.LightTokenHot,
 758→            address,
 759→            amount: parsed.parsed.amount,
 760→            accountInfo: onchainAccount,
 761→            parsed: parsed.parsed,
 762→        });
 763→    }
 764→
 765→    // Collect compressed light-token accounts (cold balance)
 766→    for (const compressedAccount of compressedAccounts) {
 767→        if (
 768→            compressedAccount &&
 769→            compressedAccount.data &&
 770→            compressedAccount.data.data.length > 0 &&
 771→            compressedAccount.owner.equals(LIGHT_TOKEN_PROGRAM_ID)
 772→        ) {
 773→            const parsed = parseLightTokenCold(address, compressedAccount);
 774→            sources.push({
 775→                type: TokenAccountSourceType.LightTokenCold,
 776→                address,
 777→                amount: parsed.parsed.amount,
 778→                accountInfo: parsed.accountInfo,
 779→                loadContext: parsed.loadContext,
 780→                parsed: parsed.parsed,
 781→            });
 782→        }
 783→    }
 784→
 785→    if (sources.length === 0) {
 786→        throw new TokenAccountNotFoundError();
 787→    }
 788→
 789→    // Priority: hot > cold
 790→    sources.sort((a, b) => {
 791→        if (a.type === 'light-token-hot' && b.type === 'light-token-cold')
 792→            return -1;
 793→        if (a.type === 'light-token-cold' && b.type === 'light-token-hot')
 794→            return 1;
 795→        return 0;
 796→    });
 797→
 798→    return buildAccountInterfaceFromSources(sources, address);
 799→}
