 894→/** @internal */
 895→export function buildAccountInterfaceFromSources(
 896→    sources: TokenAccountSource[],
 897→    canonicalAddress: PublicKey,
 898→): AccountInterface {
 899→    const totalAmount = sources.reduce(
 900→        (sum, src) => sum + src.amount,
 901→        BigInt(0),
 902→    );
 903→
 904→    const primarySource = sources[0];
 905→
 906→    const hasDelegate = sources.some(src => src.parsed.delegate !== null);
 907→    const anyFrozen = sources.some(src => src.parsed.isFrozen);
 908→    const hasColdSource = sources.some(src => isColdSourceType(src.type));
 909→    const needsConsolidation = sources.length > 1;
 910→    const delegatedContribution = (src: TokenAccountSource): bigint => {
 911→        const delegated = src.parsed.delegatedAmount ?? src.amount;
 912→        return src.amount < delegated ? src.amount : delegated;
 913→    };
 914→
 915→    const sumForDelegate = (
 916→        candidate: PublicKey,
 917→        scope: (src: TokenAccountSource) => boolean,
 918→    ): bigint =>
 919→        sources.reduce((sum, src) => {
 920→            if (!scope(src)) return sum;
 921→            const delegate = src.parsed.delegate;
 922→            if (!delegate || !delegate.equals(candidate)) return sum;
 923→            return sum + delegatedContribution(src);
 924→        }, BigInt(0));
 925→
 926→    const hotDelegatedSource = sources.find(
 927→        src => !isColdSourceType(src.type) && src.parsed.delegate !== null,
 928→    );
 929→    const coldDelegatedSources = sources.filter(
 930→        src => isColdSourceType(src.type) && src.parsed.delegate !== null,
 931→    );
 932→
 933→    let canonicalDelegate: PublicKey | null = null;
 934→    let canonicalDelegatedAmount = BigInt(0);
 935→
 936→    if (hotDelegatedSource?.parsed.delegate) {
 937→        // If any hot source is delegated, it always determines canonical delegate.
 938→        // Cold delegates only contribute when they match this hot delegate.
 939→        canonicalDelegate = hotDelegatedSource.parsed.delegate;
 940→        canonicalDelegatedAmount = sumForDelegate(
 941→            canonicalDelegate,
 942→            () => true,
 943→        );
 944→    } else if (coldDelegatedSources.length > 0) {
 945→        // No hot delegate: canonical delegate is taken from the most recent
 946→        // delegated cold source in source order (source[0] is most recent).
 947→        canonicalDelegate = coldDelegatedSources[0].parsed.delegate!;
 948→        canonicalDelegatedAmount = sumForDelegate(canonicalDelegate, src =>
 949→            isColdSourceType(src.type),
 950→        );
 951→    }
 952→
 953→    const unifiedAccount: Account = {
 954→        ...primarySource.parsed,
 955→        address: canonicalAddress,
 956→        amount: totalAmount,
 957→        // Synthetic ATA view models post-load state; any cold source implies initialized.
 958→        isInitialized: primarySource.parsed.isInitialized || hasColdSource,
 959→        delegate: canonicalDelegate,
 960→        delegatedAmount: canonicalDelegatedAmount,
 961→        ...(anyFrozen ? { state: AccountState.Frozen, isFrozen: true } : {}),
 962→    };
 963→
 964→    return {
 965→        accountInfo: primarySource.accountInfo!,
 966→        parsed: unifiedAccount,
 967→        isCold: isColdSourceType(primarySource.type),
 968→        loadContext: primarySource.loadContext,
 969→        _sources: sources,
 970→        _needsConsolidation: needsConsolidation,
 971→        _hasDelegate: hasDelegate,
 972→        _anyFrozen: anyFrozen,
 973→    };
 974→}
 975→
 976→/**
 977→ * Spendable amount for a given authority (owner or delegate).
 978→ * - If authority equals the ATA owner: full parsed.amount.
 979→ * - If authority is the canonical delegate: parsed.delegatedAmount (bounded by parsed.amount).
 980→ * - Otherwise: 0.
 981→ * @internal
 982→ */
 983→export function spendableAmountForAuthority(
 984→    iface: AccountInterface,
 985→    authority: PublicKey,
 986→): bigint {
 987→    const owner = iface._owner;
 988→    if (owner && authority.equals(owner)) {
 989→        return iface.parsed.amount;
 990→    }
 991→    const delegate = iface.parsed.delegate;
 992→    if (delegate && authority.equals(delegate)) {
 993→        const delegated = iface.parsed.delegatedAmount ?? BigInt(0);
 994→        return delegated < iface.parsed.amount
 995→            ? delegated
 996→            : iface.parsed.amount;
 997→    }
 998→    return BigInt(0);
 999→}
1000→
1001→/**
1002→ * Whether the given authority can sign for this ATA (owner or canonical delegate).
1003→ * @internal
1004→ */
1005→export function isAuthorityForInterface(
1006→    iface: AccountInterface,
1007→    authority: PublicKey,
1008→): boolean {
1009→    const owner = iface._owner;
1010→    if (owner && authority.equals(owner)) return true;
1011→    const delegate = iface.parsed.delegate;
1012→    return delegate !== null && authority.equals(delegate);
1013→}
1014→
1015→/**
1016→ * @internal
1017→ * Canonical authority projection for owner/delegate checks.
1018→ */
1019→export function filterInterfaceForAuthority(
1020→    iface: AccountInterface,
1021→    authority: PublicKey,
1022→): AccountInterface {
1023→    const owner = iface._owner;
1024→    if (owner && authority.equals(owner)) {
1025→        return iface;
1026→    }
1027→    const spendable = spendableAmountForAuthority(iface, authority);
1028→    const canonicalDelegate = iface.parsed.delegate;
1029→    if (
1030→        spendable === BigInt(0) ||
1031→        canonicalDelegate === null ||
1032→        !authority.equals(canonicalDelegate)
1033→    ) {
1034→        return {
1035→            ...iface,
1036→            _sources: [],
1037→            _needsConsolidation: false,
1038→            parsed: { ...iface.parsed, amount: BigInt(0) },
1039→        };
1040→    }
1041→    const sources = iface._sources ?? [];
1042→    const filtered = sources.filter(
1043→        src =>
1044→            src.parsed.delegate !== null &&
1045→            src.parsed.delegate.equals(canonicalDelegate),
1046→    );
1047→    const primary = filtered[0];
1048→    return {
1049→        ...iface,
1050→        ...(primary
1051→            ? {
1052→                  accountInfo: primary.accountInfo!,
1053→                  isCold: isColdSourceType(primary.type),
1054→                  loadContext: primary.loadContext,
1055→              }
1056→            : {}),
1057→        _sources: filtered,
1058→        _needsConsolidation: filtered.length > 1,
1059→        parsed: {
1060→            ...iface.parsed,
1061→            amount: spendable,
1062→        },
1063→    };
1064→}
