30→export async function loadAta(
31→    rpc: Rpc,
32→    ata: PublicKey,
33→    owner: Signer,
34→    mint: PublicKey,
35→    payer?: Signer,
36→    confirmOptions?: ConfirmOptions,
37→    interfaceOptions?: InterfaceOptions,
38→    wrap = false,
39→    decimals?: number,
40→): Promise<TransactionSignature | null> {
41→    assertBetaEnabled();
42→
43→    payer ??= owner;
44→
45→    const resolvedDecimals =
46→        decimals ?? (await getMintInterface(rpc, mint)).mint.decimals;
47→    const batches = await createLoadAtaInstructions(
48→        rpc,
49→        ata,
50→        owner.publicKey,
51→        mint,
52→        resolvedDecimals,
53→        payer.publicKey,
54→        interfaceOptions,
55→        wrap,
56→    );
57→
58→    if (batches.length === 0) {
59→        return null;
60→    }
61→
62→    const additionalSigners = dedupeSigner(payer, [owner]);
63→
64→    const txPromises = batches.map(async ixs => {
65→        const { blockhash } = await rpc.getLatestBlockhash();
66→        const tx = buildAndSignTx(ixs, payer!, blockhash, additionalSigners);
67→        return sendAndConfirmTx(rpc, tx, confirmOptions);
68→    });
69→
70→    const results = await Promise.all(txPromises);
71→    return results[results.length - 1];
72→}
