105→/**
106→ * Create a light-token transfer_checked instruction. Same semantics as SPL
107→ * TransferChecked.
108→ */
109→export function createLightTokenTransferCheckedInstruction(
110→    source: PublicKey,
111→    destination: PublicKey,
112→    mint: PublicKey,
113→    owner: PublicKey,
114→    amount: number | bigint,
115→    decimals: number,
116→    payer: PublicKey,
117→): TransactionInstruction {
118→    const data = Buffer.alloc(10);
119→    data.writeUInt8(LIGHT_TOKEN_TRANSFER_CHECKED_DISCRIMINATOR, 0);
120→    data.writeBigUInt64LE(BigInt(amount), 1);
121→    data.writeUInt8(decimals, 9);
122→
123→    const keys = [
124→        { pubkey: source, isSigner: false, isWritable: true },
125→        { pubkey: mint, isSigner: false, isWritable: false },
126→        { pubkey: destination, isSigner: false, isWritable: true },
127→        { pubkey: owner, isSigner: true, isWritable: true },
128→        { pubkey: SystemProgram.programId, isSigner: false, isWritable: false },
129→        {
130→            pubkey: payer,
131→            isSigner: true,
132→            isWritable: true,
133→        },
134→    ];
135→
136→    return new TransactionInstruction({
137→        programId: LIGHT_TOKEN_PROGRAM_ID,
138→        keys,
139→        data,
140→    });
141→}
