154→export { AtaType } from '../ata-utils';
155→
156→export async function createLoadAtaInstructions(
157→    rpc: Rpc,
158→    ata: PublicKey,
159→    owner: PublicKey,
160→    mint: PublicKey,
161→    decimals: number,
162→    payer?: PublicKey,
163→    interfaceOptions?: InterfaceOptions,
164→    wrap = false,
165→): Promise<TransactionInstruction[][]> {
166→    assertBetaEnabled();
167→    payer ??= owner;
168→
169→    const effectiveOwner = interfaceOptions?.owner ?? owner;
170→
171→    let accountInterface: AccountInterface;
172→    try {
173→        accountInterface = await _getAtaInterface(
174→            rpc,
175→            ata,
176→            effectiveOwner,
177→            mint,
178→            undefined,
179→            undefined,
180→            wrap,
181→        );
182→    } catch (e) {
183→        if (e instanceof TokenAccountNotFoundError) {
184→            return [];
185→        }
186→        throw e;
187→    }
188→
189→    const isDelegate = !effectiveOwner.equals(owner);
190→    if (isDelegate) {
191→        if (!isAuthorityForInterface(accountInterface, owner)) {
192→            throw new Error(
193→                'Signer is not the owner or a delegate of the account.',
194→            );
195→        }
196→        accountInterface = filterInterfaceForAuthority(accountInterface, owner);
197→    }
198→
199→    const internalBatches = await _buildLoadBatches(
200→        rpc,
201→        payer,
202→        accountInterface,
203→        interfaceOptions,
204→        wrap,
205→        ata,
206→        undefined,
207→        owner,
208→        decimals,
209→    );
210→
211→    return internalBatches.map(batch => [
212→        ComputeBudgetProgram.setComputeUnitLimit({
213→            units: calculateLoadBatchComputeUnits(batch),
214→        }),
215→        ...batch.instructions,
216→    ]);
217→}
218→
219→export interface InternalLoadBatch {
220→    instructions: TransactionInstruction[];
221→    compressedAccounts: ParsedTokenAccount[];
222→    wrapCount: number;
223→    hasAtaCreation: boolean;
224→}
225→
226→const CU_ATA_CREATION = 30_000;
227→const CU_WRAP = 50_000;
228→const CU_DECOMPRESS_BASE = 50_000;
229→const CU_FULL_PROOF = 100_000;
230→const CU_PER_ACCOUNT_PROVE_BY_INDEX = 10_000;
231→const CU_PER_ACCOUNT_FULL_PROOF = 30_000;
232→const CU_BUFFER_FACTOR = 1.3;
233→const CU_MIN = 50_000;
234→const CU_MAX = 1_400_000;
235→
236→export function rawLoadBatchComputeUnits(batch: InternalLoadBatch): number {
237→    let cu = 0;
238→    if (batch.hasAtaCreation) cu += CU_ATA_CREATION;
239→    cu += batch.wrapCount * CU_WRAP;
240→    if (batch.compressedAccounts.length > 0) {
241→        cu += CU_DECOMPRESS_BASE;
242→        const needsFullProof = batch.compressedAccounts.some(
243→            acc => !(acc.compressedAccount.proveByIndex ?? false),
244→        );
245→        if (needsFullProof) cu += CU_FULL_PROOF;
246→        for (const acc of batch.compressedAccounts) {
247→            cu +=
248→                (acc.compressedAccount.proveByIndex ?? false)
249→                    ? CU_PER_ACCOUNT_PROVE_BY_INDEX
250→                    : CU_PER_ACCOUNT_FULL_PROOF;
251→        }
252→    }
253→    return cu;
254→}
255→
256→export function calculateLoadBatchComputeUnits(
257→    batch: InternalLoadBatch,
258→): number {
259→    const cu = Math.ceil(rawLoadBatchComputeUnits(batch) * CU_BUFFER_FACTOR);
260→    return Math.max(CU_MIN, Math.min(CU_MAX, cu));
261→}
262→
263→export async function _buildLoadBatches(
264→    rpc: Rpc,
265→    payer: PublicKey,
266→    ata: AccountInterface,
267→    options: InterfaceOptions | undefined,
268→    wrap: boolean,
269→    targetAta: PublicKey,
270→    targetAmount: bigint | undefined,
271→    authority: PublicKey | undefined,
272→    decimals: number,
273→): Promise<InternalLoadBatch[]> {
274→    if (!ata._isAta || !ata._owner || !ata._mint) {
275→        throw new Error(
276→            'AccountInterface must be from getAtaInterface (requires _isAta, _owner, _mint)',
277→        );
278→    }
279→
280→    assertNotFrozen(ata, 'load');
281→
282→    const owner = ata._owner;
283→    const mint = ata._mint;
284→    const sources = ata._sources ?? [];
285→
286→    const allCompressedAccounts =
287→        getCompressedTokenAccountsFromAtaSources(sources);
288→
289→    const lightTokenAtaAddress = getAssociatedTokenAddressInterface(
290→        mint,
291→        owner,
292→    );
293→    const splAta = getAssociatedTokenAddressSync(
294→        mint,
295→        owner,
296→        false,
297→        TOKEN_PROGRAM_ID,
298→        getAtaProgramId(TOKEN_PROGRAM_ID),
299→    );
300→    const t22Ata = getAssociatedTokenAddressSync(
301→        mint,
302→        owner,
303→        false,
304→        TOKEN_2022_PROGRAM_ID,
305→        getAtaProgramId(TOKEN_2022_PROGRAM_ID),
306→    );
307→
308→    let ataType: AtaType = 'light-token';
309→    const validation = checkAtaAddress(targetAta, mint, owner);
310→    ataType = validation.type;
311→    if (wrap && ataType !== 'light-token') {
312→        throw new Error(
313→            `For wrap=true, targetAta must be light-token associated token account. Got ${ataType} associated token account.`,
314→        );
315→    }
316→
317→    const splSource = sources.find(s => s.type === 'spl');
318→    const t22Source = sources.find(s => s.type === 'token2022');
319→    const lightTokenHotSource = sources.find(s => s.type === 'light-token-hot');
320→    const coldSources = sources.filter(s => COLD_SOURCE_TYPES.has(s.type));
321→
322→    const splBalance = splSource?.amount ?? BigInt(0);
323→    const t22Balance = t22Source?.amount ?? BigInt(0);
324→    const coldBalance = coldSources.reduce(
325→        (sum, s) => sum + s.amount,
326→        BigInt(0),
327→    );
328→
329→    if (
330→        splBalance === BigInt(0) &&
331→        t22Balance === BigInt(0) &&
332→        coldBalance === BigInt(0)
333→    ) {
334→        return [];
335→    }
336→
337→    let splInterfaceInfo: SplInterfaceInfo | undefined;
338→    const needsSplInfo =
339→        wrap ||
340→        ataType === 'spl' ||
341→        ataType === 'token2022' ||
342→        splBalance > BigInt(0) ||
343→        t22Balance > BigInt(0);
344→    if (needsSplInfo) {
345→        try {
346→            const splInterfaceInfos =
347→                options?.splInterfaceInfos ??
348→                (await getSplInterfaceInfos(rpc, mint));
349→            splInterfaceInfo = splInterfaceInfos.find(
350→                (info: SplInterfaceInfo) => info.isInitialized,
351→            );
352→        } catch (e) {
353→            if (splBalance > BigInt(0) || t22Balance > BigInt(0)) {
354→                throw e;
355→            }
356→        }
357→    }
358→
359→    const setupInstructions: TransactionInstruction[] = [];
360→    let wrapCount = 0;
361→    let needsAtaCreation = false;
362→
363→    let decompressTarget: PublicKey = lightTokenAtaAddress;
364→    let decompressSplInfo: SplInterfaceInfo | undefined;
365→    let canDecompress = false;
366→
367→    if (wrap) {
368→        decompressTarget = lightTokenAtaAddress;
369→        decompressSplInfo = undefined;
370→        canDecompress = true;
371→
372→        if (!lightTokenHotSource) {
373→            needsAtaCreation = true;
374→            setupInstructions.push(
375→                createAssociatedTokenAccountInterfaceIdempotentInstruction(
376→                    payer,
377→                    lightTokenAtaAddress,
378→                    owner,
379→                    mint,
380→                    LIGHT_TOKEN_PROGRAM_ID,
381→                ),
382→            );
383→        }
384→
385→        if (splBalance > BigInt(0) && splInterfaceInfo) {
386→            setupInstructions.push(
387→                createWrapInstruction(
388→                    splAta,
389→                    lightTokenAtaAddress,
390→                    owner,
391→                    mint,
392→                    splBalance,
393→                    splInterfaceInfo,
394→                    decimals,
395→                    payer,
396→                ),
397→            );
398→            wrapCount++;
399→        }
400→
401→        if (t22Balance > BigInt(0) && splInterfaceInfo) {
402→            setupInstructions.push(
403→                createWrapInstruction(
404→                    t22Ata,
405→                    lightTokenAtaAddress,
406→                    owner,
407→                    mint,
408→                    t22Balance,
409→                    splInterfaceInfo,
410→                    decimals,
411→                    payer,
412→                ),
413→            );
414→            wrapCount++;
415→        }
416→    } else {
417→        if (ataType === 'light-token') {
418→            decompressTarget = lightTokenAtaAddress;
419→            decompressSplInfo = undefined;
420→            canDecompress = true;
421→            if (!lightTokenHotSource) {
422→                needsAtaCreation = true;
423→                setupInstructions.push(
424→                    createAssociatedTokenAccountInterfaceIdempotentInstruction(
425→                        payer,
426→                        lightTokenAtaAddress,
427→                        owner,
428→                        mint,
429→                        LIGHT_TOKEN_PROGRAM_ID,
430→                    ),
431→                );
432→            }
433→        } else if (ataType === 'spl' && splInterfaceInfo) {
434→            decompressTarget = splAta;
435→            decompressSplInfo = splInterfaceInfo;
436→            canDecompress = true;
437→            if (!splSource) {
438→                needsAtaCreation = true;
439→                setupInstructions.push(
440→                    createAssociatedTokenAccountIdempotentInstruction(
441→                        payer,
442→                        splAta,
443→                        owner,
444→                        mint,
445→                        TOKEN_PROGRAM_ID,
446→                    ),
447→                );
448→            }
449→        } else if (ataType === 'token2022' && splInterfaceInfo) {
450→            decompressTarget = t22Ata;
451→            decompressSplInfo = splInterfaceInfo;
452→            canDecompress = true;
453→            if (!t22Source) {
454→                needsAtaCreation = true;
455→                setupInstructions.push(
456→                    createAssociatedTokenAccountIdempotentInstruction(
457→                        payer,
458→                        t22Ata,
459→                        owner,
460→                        mint,
461→                        TOKEN_2022_PROGRAM_ID,
462→                    ),
463→                );
464→            }
465→        }
466→    }
467→
468→    let accountsToLoad = allCompressedAccounts;
469→
470→    if (
471→        targetAmount !== undefined &&
472→        canDecompress &&
473→        allCompressedAccounts.length > 0
474→    ) {
475→        const isDelegate = authority !== undefined && !authority.equals(owner);
476→        const hotBalance = (() => {
477→            if (!lightTokenHotSource) return BigInt(0);
478→            if (isDelegate) {
479→                const delegated =
480→                    lightTokenHotSource.parsed.delegatedAmount ?? BigInt(0);
481→                return delegated < lightTokenHotSource.amount
482→                    ? delegated
483→                    : lightTokenHotSource.amount;
484→            }
485→            return lightTokenHotSource.amount;
486→        })();
487→        let effectiveHotAfterSetup: bigint;
488→
489→        if (wrap) {
490→            effectiveHotAfterSetup = hotBalance + splBalance + t22Balance;
491→        } else if (ataType === 'light-token') {
492→            effectiveHotAfterSetup = hotBalance;
493→        } else if (ataType === 'spl') {
494→            effectiveHotAfterSetup = splBalance;
495→        } else {
496→            effectiveHotAfterSetup = t22Balance;
497→        }
498→
499→        const neededFromCold =
500→            targetAmount > effectiveHotAfterSetup
501→                ? targetAmount - effectiveHotAfterSetup
502→                : BigInt(0);
503→
504→        if (neededFromCold === BigInt(0)) {
505→            accountsToLoad = [];
506→        } else {
507→            accountsToLoad = selectInputsForAmount(
508→                allCompressedAccounts,
509→                neededFromCold,
510→            );
511→        }
512→    }
513→
514→    if (!canDecompress || accountsToLoad.length === 0) {
515→        if (setupInstructions.length === 0) return [];
516→        return [
517→            {
518→                instructions: setupInstructions,
519→                compressedAccounts: [],
520→                wrapCount,
521→                hasAtaCreation: needsAtaCreation,
522→            },
523→        ];
524→    }
525→
526→    assertV2Only(accountsToLoad);
527→
528→    const chunks = chunkArray(accountsToLoad, MAX_INPUT_ACCOUNTS);
529→    assertUniqueInputHashes(chunks);
530→
531→    const proofs = await Promise.all(
532→        chunks.map(async chunk => {
533→            const proofInputs = chunk.map(acc => ({
534→                hash: acc.compressedAccount.hash,
535→                tree: acc.compressedAccount.treeInfo.tree,
536→                queue: acc.compressedAccount.treeInfo.queue,
537→            }));
538→            return rpc.getValidityProofV0(proofInputs);
539→        }),
540→    );
541→
542→    const idempotentAtaIx = (() => {
543→        if (wrap || ataType === 'light-token') {
544→            return createAssociatedTokenAccountInterfaceIdempotentInstruction(
545→                payer,
546→                lightTokenAtaAddress,
547→                owner,
548→                mint,
549→                LIGHT_TOKEN_PROGRAM_ID,
550→            );
551→        } else if (ataType === 'spl') {
552→            return createAssociatedTokenAccountIdempotentInstruction(
553→                payer,
554→                splAta,
555→                owner,
556→                mint,
557→                TOKEN_PROGRAM_ID,
558→            );
559→        } else {
560→            return createAssociatedTokenAccountIdempotentInstruction(
561→                payer,
562→                t22Ata,
563→                owner,
564→                mint,
565→                TOKEN_2022_PROGRAM_ID,
566→            );
567→        }
568→    })();
569→
570→    const batches: InternalLoadBatch[] = [];
571→
572→    for (let i = 0; i < chunks.length; i++) {
573→        const chunk = chunks[i];
574→        const proof = proofs[i];
575→        const chunkAmount = chunk.reduce(
576→            (sum, acc) => sum + BigInt(acc.parsed.amount.toString()),
577→            BigInt(0),
578→        );
579→
580→        const batchIxs: TransactionInstruction[] = [];
581→        let batchWrapCount = 0;
582→        let batchHasAtaCreation = false;
583→
584→        if (i === 0) {
585→            batchIxs.push(...setupInstructions);
586→            batchWrapCount = wrapCount;
587→            batchHasAtaCreation = needsAtaCreation;
588→        } else {
589→            batchIxs.push(idempotentAtaIx);
590→            batchHasAtaCreation = true;
591→        }
592→
593→        const authorityForDecompress = authority ?? owner;
594→        batchIxs.push(
595→            createDecompressInterfaceInstruction(
596→                payer,
597→                chunk,
598→                decompressTarget,
599→                chunkAmount,
600→                proof,
601→                decompressSplInfo,
602→                decimals,
603→                undefined,
604→                authorityForDecompress,
605→            ),
606→        );
607→
608→        batches.push({
609→            instructions: batchIxs,
610→            compressedAccounts: chunk,
611→            wrapCount: batchWrapCount,
612→            hasAtaCreation: batchHasAtaCreation,
613→        });
614→    }
615→
616→    return batches;
617→}
