  1→import {
  2→    Rpc,
  3→    LIGHT_TOKEN_PROGRAM_ID,
  4→    ParsedTokenAccount,
  5→    bn,
  6→    assertBetaEnabled,
  7→} from '@lightprotocol/stateless.js';
  8→import { assertV2Only } from '../assert-v2-only';
  9→import {
 10→    ComputeBudgetProgram,
 11→    PublicKey,
 12→    TransactionInstruction,
 13→} from '@solana/web3.js';
 14→import {
 15→    TOKEN_PROGRAM_ID,
 16→    TOKEN_2022_PROGRAM_ID,
 17→    getAssociatedTokenAddressSync,
 18→    createAssociatedTokenAccountIdempotentInstruction,
 19→    TokenAccountNotFoundError,
 20→} from '@solana/spl-token';
 21→import {
 22→    AccountInterface,
 23→    assertNotFrozen,
 24→    COLD_SOURCE_TYPES,
 25→    getAtaInterface as _getAtaInterface,
 26→    TokenAccountSource,
 27→    isAuthorityForInterface,
 28→    filterInterfaceForAuthority,
 29→} from '../get-account-interface';
 30→import { getAssociatedTokenAddressInterface } from '../get-associated-token-address-interface';
 31→import { createAssociatedTokenAccountInterfaceIdempotentInstruction } from './create-ata-interface';
 32→import { createWrapInstruction } from './wrap';
 33→import { createDecompressInterfaceInstruction } from './create-decompress-interface-instruction';
 34→import {
 35→    getSplInterfaceInfos,
 36→    SplInterfaceInfo,
 37→} from '../../utils/get-token-pool-infos';
 38→import { getAtaProgramId, checkAtaAddress, AtaType } from '../ata-utils';
 39→import type { InterfaceOptions } from '../actions/transfer-interface';
 40→
 41→export const MAX_INPUT_ACCOUNTS = 8;
 42→
 43→function chunkArray<T>(array: T[], chunkSize: number): T[][] {
 44→    const chunks: T[][] = [];
 45→    for (let i = 0; i < array.length; i += chunkSize) {
 46→        chunks.push(array.slice(i, i + chunkSize));
 47→    }
 48→    return chunks;
 49→}
 50→
 51→export function selectInputsForAmount(
 52→    accounts: ParsedTokenAccount[],
 53→    neededAmount: bigint,
 54→): ParsedTokenAccount[] {
 55→    if (accounts.length === 0 || neededAmount <= BigInt(0)) return [];
 56→
 57→    const sorted = [...accounts].sort((a, b) => {
 58→        const amtA = BigInt(a.parsed.amount.toString());
 59→        const amtB = BigInt(b.parsed.amount.toString());
 60→        if (amtB > amtA) return 1;
 61→        if (amtB < amtA) return -1;
 62→        return 0;
 63→    });
 64→
 65→    let accumulated = BigInt(0);
 66→    let countNeeded = 0;
 67→    for (const acc of sorted) {
 68→        countNeeded++;
 69→        accumulated += BigInt(acc.parsed.amount.toString());
 70→        if (accumulated >= neededAmount) break;
 71→    }
 72→
 73→    const selectCount = Math.min(
 74→        Math.max(countNeeded, MAX_INPUT_ACCOUNTS),
 75→        sorted.length,
 76→    );
 77→
 78→    return sorted.slice(0, selectCount);
 79→}
 80→
 81→function assertUniqueInputHashes(chunks: ParsedTokenAccount[][]): void {
 82→    const seen = new Set<string>();
 83→    for (const chunk of chunks) {
 84→        for (const acc of chunk) {
 85→            const hashStr = acc.compressedAccount.hash.toString();
 86→            if (seen.has(hashStr)) {
 87→                throw new Error(
 88→                    `Duplicate compressed account hash across chunks: ${hashStr}. ` +
 89→                        `Each compressed account must appear in exactly one chunk.`,
 90→                );
 91→            }
 92→            seen.add(hashStr);
 93→        }
 94→    }
 95→}
 96→
 97→export function getCompressedTokenAccountsFromAtaSources(
 98→    sources: TokenAccountSource[],
 99→): ParsedTokenAccount[] {
100→    return sources
101→        .filter(source => source.loadContext !== undefined)
102→        .filter(source => COLD_SOURCE_TYPES.has(source.type))
103→        .map(source => {
104→            const fullData = source.accountInfo.data;
105→            const discriminatorBytes = fullData.subarray(
106→                0,
107→                Math.min(8, fullData.length),
108→            );
109→            const accountDataBytes =
110→                fullData.length > 8 ? fullData.subarray(8) : Buffer.alloc(0);
111→
112→            const compressedAccount = {
113→                treeInfo: source.loadContext!.treeInfo,
114→                hash: source.loadContext!.hash,
115→                leafIndex: source.loadContext!.leafIndex,
116→                proveByIndex: source.loadContext!.proveByIndex,
117→                owner: source.accountInfo.owner,
118→                lamports: bn(source.accountInfo.lamports),
119→                address: null,
120→                data:
121→                    fullData.length === 0
122→                        ? null
123→                        : {
124→                              discriminator: Array.from(discriminatorBytes),
125→                              data: Buffer.from(accountDataBytes),
126→                              dataHash: new Array(32).fill(0),
127→                          },
128→                readOnly: false,
129→            };
130→
131→            const state = !source.parsed.isInitialized
132→                ? 0
133→                : source.parsed.isFrozen
134→                  ? 2
135→                  : 1;
136→
137→            return {
138→                compressedAccount: compressedAccount as any,
139→                parsed: {
140→                    mint: source.parsed.mint,
141→                    owner: source.parsed.owner,
142→                    amount: bn(source.parsed.amount.toString()),
143→                    delegate: source.parsed.delegate,
144→                    state,
145→                    tlv:
146→                        source.parsed.tlvData.length > 0
147→                            ? source.parsed.tlvData
148→                            : null,
149→                },
150→            } satisfies ParsedTokenAccount;
151→        });
152→}
153→
154→export { AtaType } from '../ata-utils';
155→
156→export async function createLoadAtaInstructions(
157→    rpc: Rpc,
158→    ata: PublicKey,
159→    owner: PublicKey,
160→    mint: PublicKey,
161→    decimals: number,
162→    payer?: PublicKey,
163→    interfaceOptions?: InterfaceOptions,
164→    wrap = false,
165→): Promise<TransactionInstruction[][]> {
166→    assertBetaEnabled();
167→    payer ??= owner;
168→
169→    const effectiveOwner = interfaceOptions?.owner ?? owner;
170→
171→    let accountInterface: AccountInterface;
172→    try {
173→        accountInterface = await _getAtaInterface(
174→            rpc,
175→            ata,
176→            effectiveOwner,
177→            mint,
178→            undefined,
179→            undefined,
180→            wrap,
181→        );
182→    } catch (e) {
183→        if (e instanceof TokenAccountNotFoundError) {
184→            return [];
185→        }
186→        throw e;
187→    }
188→
189→    const isDelegate = !effectiveOwner.equals(owner);
190→    if (isDelegate) {
191→        if (!isAuthorityForInterface(accountInterface, owner)) {
192→            throw new Error(
193→                'Signer is not the owner or a delegate of the account.',
194→            );
195→        }
196→        accountInterface = filterInterfaceForAuthority(accountInterface, owner);
197→    }
198→
199→    const internalBatches = await _buildLoadBatches(
200→        rpc,
201→        payer,
202→        accountInterface,
203→        interfaceOptions,
204→        wrap,
205→        ata,
206→        undefined,
207→        owner,
208→        decimals,
209→    );
210→
211→    return internalBatches.map(batch => [
212→        ComputeBudgetProgram.setComputeUnitLimit({
213→            units: calculateLoadBatchComputeUnits(batch),
214→        }),
215→        ...batch.instructions,
216→    ]);
217→}
218→
219→export interface InternalLoadBatch {
220→    instructions: TransactionInstruction[];
221→    compressedAccounts: ParsedTokenAccount[];
222→    wrapCount: number;
223→    hasAtaCreation: boolean;
224→}
225→
226→const CU_ATA_CREATION = 30_000;
227→const CU_WRAP = 50_000;
228→const CU_DECOMPRESS_BASE = 50_000;
229→const CU_FULL_PROOF = 100_000;
230→const CU_PER_ACCOUNT_PROVE_BY_INDEX = 10_000;
231→const CU_PER_ACCOUNT_FULL_PROOF = 30_000;
232→const CU_BUFFER_FACTOR = 1.3;
233→const CU_MIN = 50_000;
234→const CU_MAX = 1_400_000;
235→
236→export function rawLoadBatchComputeUnits(batch: InternalLoadBatch): number {
237→    let cu = 0;
238→    if (batch.hasAtaCreation) cu += CU_ATA_CREATION;
239→    cu += batch.wrapCount * CU_WRAP;
240→    if (batch.compressedAccounts.length > 0) {
241→        cu += CU_DECOMPRESS_BASE;
242→        const needsFullProof = batch.compressedAccounts.some(
243→            acc => !(acc.compressedAccount.proveByIndex ?? false),
244→        );
245→        if (needsFullProof) cu += CU_FULL_PROOF;
246→        for (const acc of batch.compressedAccounts) {
247→            cu +=
248→                (acc.compressedAccount.proveByIndex ?? false)
249→                    ? CU_PER_ACCOUNT_PROVE_BY_INDEX
250→                    : CU_PER_ACCOUNT_FULL_PROOF;
251→        }
252→    }
253→    return cu;
254→}
255→
256→export function calculateLoadBatchComputeUnits(
257→    batch: InternalLoadBatch,
258→): number {
259→    const cu = Math.ceil(rawLoadBatchComputeUnits(batch) * CU_BUFFER_FACTOR);
260→    return Math.max(CU_MIN, Math.min(CU_MAX, cu));
261→}
262→
263→export async function _buildLoadBatches(
264→    rpc: Rpc,
265→    payer: PublicKey,
266→    ata: AccountInterface,
267→    options: InterfaceOptions | undefined,
268→    wrap: boolean,
269→    targetAta: PublicKey,
270→    targetAmount: bigint | undefined,
271→    authority: PublicKey | undefined,
272→    decimals: number,
273→): Promise<InternalLoadBatch[]> {
274→    if (!ata._isAta || !ata._owner || !ata._mint) {
275→        throw new Error(
276→            'AccountInterface must be from getAtaInterface (requires _isAta, _owner, _mint)',
277→        );
278→    }
279→
280→    assertNotFrozen(ata, 'load');
281→
282→    const owner = ata._owner;
283→    const mint = ata._mint;
284→    const sources = ata._sources ?? [];
285→
286→    const allCompressedAccounts =
287→        getCompressedTokenAccountsFromAtaSources(sources);
288→
289→    const lightTokenAtaAddress = getAssociatedTokenAddressInterface(
290→        mint,
291→        owner,
292→    );
293→    const splAta = getAssociatedTokenAddressSync(
294→        mint,
295→        owner,
296→        false,
297→        TOKEN_PROGRAM_ID,
298→        getAtaProgramId(TOKEN_PROGRAM_ID),
299→    );
300→    const t22Ata = getAssociatedTokenAddressSync(
301→        mint,
302→        owner,
303→        false,
304→        TOKEN_2022_PROGRAM_ID,
305→        getAtaProgramId(TOKEN_2022_PROGRAM_ID),
306→    );
307→
308→    let ataType: AtaType = 'light-token';
309→    const validation = checkAtaAddress(targetAta, mint, owner);
310→    ataType = validation.type;
311→    if (wrap && ataType !== 'light-token') {
312→        throw new Error(
313→            `For wrap=true, targetAta must be light-token associated token account. Got ${ataType} associated token account.`,
314→        );
315→    }
316→
317→    const splSource = sources.find(s => s.type === 'spl');
318→    const t22Source = sources.find(s => s.type === 'token2022');
319→    const lightTokenHotSource = sources.find(s => s.type === 'light-token-hot');
320→    const coldSources = sources.filter(s => COLD_SOURCE_TYPES.has(s.type));
321→
322→    const splBalance = splSource?.amount ?? BigInt(0);
323→    const t22Balance = t22Source?.amount ?? BigInt(0);
324→    const coldBalance = coldSources.reduce(
325→        (sum, s) => sum + s.amount,
326→        BigInt(0),
327→    );
328→
329→    if (
330→        splBalance === BigInt(0) &&
331→        t22Balance === BigInt(0) &&
332→        coldBalance === BigInt(0)
333→    ) {
334→        return [];
335→    }
336→
337→    let splInterfaceInfo: SplInterfaceInfo | undefined;
338→    const needsSplInfo =
339→        wrap ||
340→        ataType === 'spl' ||
341→        ataType === 'token2022' ||
342→        splBalance > BigInt(0) ||
343→        t22Balance > BigInt(0);
344→    if (needsSplInfo) {
345→        try {
346→            const splInterfaceInfos =
347→                options?.splInterfaceInfos ??
348→                (await getSplInterfaceInfos(rpc, mint));
349→            splInterfaceInfo = splInterfaceInfos.find(
350→                (info: SplInterfaceInfo) => info.isInitialized,
351→            );
352→        } catch (e) {
353→            if (splBalance > BigInt(0) || t22Balance > BigInt(0)) {
354→                throw e;
355→            }
356→        }
357→    }
358→
359→    const setupInstructions: TransactionInstruction[] = [];
360→    let wrapCount = 0;
361→    let needsAtaCreation = false;
362→
363→    let decompressTarget: PublicKey = lightTokenAtaAddress;
364→    let decompressSplInfo: SplInterfaceInfo | undefined;
365→    let canDecompress = false;
366→
367→    if (wrap) {
368→        decompressTarget = lightTokenAtaAddress;
369→        decompressSplInfo = undefined;
370→        canDecompress = true;
371→
372→        if (!lightTokenHotSource) {
373→            needsAtaCreation = true;
374→            setupInstructions.push(
375→                createAssociatedTokenAccountInterfaceIdempotentInstruction(
376→                    payer,
377→                    lightTokenAtaAddress,
378→                    owner,
379→                    mint,
380→                    LIGHT_TOKEN_PROGRAM_ID,
381→                ),
382→            );
383→        }
384→
385→        if (splBalance > BigInt(0) && splInterfaceInfo) {
386→            setupInstructions.push(
387→                createWrapInstruction(
388→                    splAta,
389→                    lightTokenAtaAddress,
390→                    owner,
391→                    mint,
392→                    splBalance,
393→                    splInterfaceInfo,
394→                    decimals,
395→                    payer,
396→                ),
397→            );
398→            wrapCount++;
399→        }
400→
401→        if (t22Balance > BigInt(0) && splInterfaceInfo) {
402→            setupInstructions.push(
403→                createWrapInstruction(
404→                    t22Ata,
405→                    lightTokenAtaAddress,
406→                    owner,
407→                    mint,
408→                    t22Balance,
409→                    splInterfaceInfo,
410→                    decimals,
411→                    payer,
412→                ),
413→            );
414→            wrapCount++;
